import{_ as t,r as s,o as i,c as o,a as e,b as a,d as h,w as d,e as n}from"./app-15e6ab5f.js";const c="/images/essay/2022/2022_1.jpg",p="/images/essay/2022/2022_2.jpg",l="/images/essay/2022/20220619.png",_={},f=n('<h1 id="_2022" tabindex="-1"><a class="header-anchor" href="#_2022" aria-hidden="true">#</a> 2022</h1><h2 id="年度总结" tabindex="-1"><a class="header-anchor" href="#年度总结" aria-hidden="true">#</a> 年度总结</h2><p>电脑端数据始于 20220428</p><p>OSU 击打键数（20220807-20221231）：6811665</p><p>跑步里程：97130 m，俯卧撑：872 个，引体向上：249.5 个</p><img alt="电脑时长（部分）" src="'+c+'" width="50%" height="50%"><img alt="手机时长" src="'+p+'" width="50%" height="50%"><h2 id="_20221220" tabindex="-1"><a class="header-anchor" href="#_20221220" aria-hidden="true">#</a> 20221220</h2><p>在午夜的黑暗中看手机，会很容易被当成目标的吧. ..呜哇</p><h2 id="_20221218" tabindex="-1"><a class="header-anchor" href="#_20221218" aria-hidden="true">#</a> 20221218</h2><p>为什么放假了才会选择看小说呢？ <span class="heimu" title="你知道的太多了">因为冷，被窝舒服，早上不想爬起床，只能玩手机，然后就只能看小说了. ..</span></p><h2 id="_20221129" tabindex="-1"><a class="header-anchor" href="#_20221129" aria-hidden="true">#</a> 20221129</h2><p>幼时，我心向光明；今日，我沉逸黑暗。</p><h2 id="_20221114" tabindex="-1"><a class="header-anchor" href="#_20221114" aria-hidden="true">#</a> 20221114</h2><p>从今以后我将作为意义党而活着。</p><hr><p>72 小时后禁止指纹解锁是我觉得 Android 机上最傻逼的设计。</p><h2 id="_20221111" tabindex="-1"><a class="header-anchor" href="#_20221111" aria-hidden="true">#</a> 20221111</h2><p>我的缓存比较大而存储比较小。因此将缓存写入存储的过程是必要的。</p><h2 id="_20221103" tabindex="-1"><a class="header-anchor" href="#_20221103" aria-hidden="true">#</a> 20221103</h2><p>看不见星光的夜空中泛着红。</p><h2 id="_20221030" tabindex="-1"><a class="header-anchor" href="#_20221030" aria-hidden="true">#</a> 20221030</h2><p>面具之下，还会是面具吗？我自己也不知道。</p><h2 id="_20221023" tabindex="-1"><a class="header-anchor" href="#_20221023" aria-hidden="true">#</a> 20221023</h2><p>享乐精神使我追求平稳安逸，经历意义又使我憧憬危难刺激；在大厦将倾的今天，我是否还能感受童年时的记忆？</p><h2 id="_20221019" tabindex="-1"><a class="header-anchor" href="#_20221019" aria-hidden="true">#</a> 20221019</h2><p>深夜在冷冽的寒风中，仰望夜空星辰，是否能唤起一些从前我对未知的渴望？</p><hr><p>饱暖思淫欲，饥寒知世艰。</p><h2 id="_20221018" tabindex="-1"><a class="header-anchor" href="#_20221018" aria-hidden="true">#</a> 20221018</h2><p>每次用 IDM 下载大文件我都好奇为什么盘盒硬盘灯不闪。。今天发现 IDM 是默认下载缓存到 C 盘再合并的。。</p><h2 id="_20221016" tabindex="-1"><a class="header-anchor" href="#_20221016" aria-hidden="true">#</a> 20221016</h2><p>激进应当是程序员的必备品质。</p><h2 id="_20221010" tabindex="-1"><a class="header-anchor" href="#_20221010" aria-hidden="true">#</a> 20221010</h2><p>很喜欢 23:00-24:00 这段时间。每天 23 点断电后，我会把笔记本亮度调到最低，加上黄得发黑的屏幕滤镜，在漆黑的小宿舍里推 galgame。寂暗的夜，我可以沉醉在屏幕后的世界中，不用想太多多余的事情；而午夜卡着时间领完每日折扣券后出门刷牙，走廊冷冽的白色淡光又能使我沉醉梦幻。</p><h2 id="_20220925" tabindex="-1"><a class="header-anchor" href="#_20220925" aria-hidden="true">#</a> 20220925</h2><p>我的爆肝小助手：冰红茶+外卖。</p><h2 id="_20220924" tabindex="-1"><a class="header-anchor" href="#_20220924" aria-hidden="true">#</a> 20220924</h2><p>在周末半黑不黑的傍晚，能感受到侵入体内的寒气中，骑着一辆辐条嘎吱响的自行车，绕着学校慢悠悠地骑行一圈，看着现充卷王们三三两两走过，胸中会涌起孤独，充实，和其他的一些说不上来的感觉。</p><h2 id="_20220917" tabindex="-1"><a class="header-anchor" href="#_20220917" aria-hidden="true">#</a> 20220917</h2><p>市面上这些四六级头戴式耳机…把耳罩做大一点会死啊…</p><h2 id="_20220914" tabindex="-1"><a class="header-anchor" href="#_20220914" aria-hidden="true">#</a> 20220914</h2><p>一个老师性格温和但啥都不会，一个老师技术大佬但脾气暴躁，当这两个老师开始轮换教学，这将是一场灾难。</p><hr><p>烈日让我舒适而迷茫，飘雨给我失落与决心。</p><h2 id="_20220829" tabindex="-1"><a class="header-anchor" href="#_20220829" aria-hidden="true">#</a> 20220829</h2><p>将返校焦虑转化为打 osu 的动力！</p><h2 id="_20220818" tabindex="-1"><a class="header-anchor" href="#_20220818" aria-hidden="true">#</a> 20220818</h2>',48),u=n('<h2 id="_20220817" tabindex="-1"><a class="header-anchor" href="#_20220817" aria-hidden="true">#</a> 20220817</h2><p>玄幻读者表示，泳池是最没有素质的公共场所<span class="heimu" title="你知道的太多了">之一</span>。</p><h2 id="_20220815" tabindex="-1"><a class="header-anchor" href="#_20220815" aria-hidden="true">#</a> 20220815</h2><p>把存档放在<code>%AppData%\\Roaming</code>里面的是坏文明！太坏了……呜…呜呜……</p><h2 id="_20220814" tabindex="-1"><a class="header-anchor" href="#_20220814" aria-hidden="true">#</a> 20220814</h2><p>蚊香液 p 用没有，还得是电蚊拍。（啊…《灭蚊记》的话还是算了吧……</p><h2 id="_20220813" tabindex="-1"><a class="header-anchor" href="#_20220813" aria-hidden="true">#</a> 20220813</h2>',7),b=e("hr",null,null,-1),x=e("p",null,[a("我希望有一间像"),e("em",null,"冥契"),a("中妹妹那样的房间，纯净而不染一丝污垢，沉醉而不想醒来，不受世俗所扰，仅需我与所爱之物便可。")],-1),m=e("hr",null,null,-1),g=e("p",null,"曾想在博客设立一个垃圾箱，用来发泄我的感情。想想还是算了。（移步频道搜 #垃圾桶）",-1),k=e("hr",null,null,-1),v=e("p",null,"Q：公交车/大巴车的哪个位置比较安全？A：左前右后。",-1),A=e("h2",{id:"_20220808",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#_20220808","aria-hidden":"true"},"#"),a(" 20220808")],-1),E=n('<h2 id="_20220730" tabindex="-1"><a class="header-anchor" href="#_20220730" aria-hidden="true">#</a> 20220730</h2><p>高中没接触那些有意义的事真是太糟了……损失了很多成长的机会。我开始后悔了。</p><hr><p>灭蟑记（五）<sup class="footnote-ref"><a href="#footnote1">[1]</a><a class="footnote-anchor" id="footnote-ref1"></a></sup></p><p>入庖厨，一蟑伏地，一蟑藏左柜边，皆不动弹。乃踏之一而拖鞋迅击之二。处理于水道，而三蟑探头于盥洗旁，困入死角，杀之。此时乃杀蟑如麻，战意沸腾之际，遂入厨四处细寻，见四蟑藏于炊具后。移釜而杀之。噫！今日四杀，吾之大胜也。此间蟑螂皆缓动呆滞，料其亲友皆亡于前日，饥而寻食，却无逃遁之速度，无对敌之经验，其亡也当然耳。</p><h2 id="_20220729" tabindex="-1"><a class="header-anchor" href="#_20220729" aria-hidden="true">#</a> 20220729</h2><p>灭蟑记（四）<sup class="footnote-ref"><a href="#footnote1">[1:1]</a><a class="footnote-anchor" id="footnote-ref1:1"></a></sup></p><p>灭一蚊，净手，忽见一稍小蟑螂伏于池边盆上。其经验不足，未逃，一击毙命。</p><h2 id="_20220725" tabindex="-1"><a class="header-anchor" href="#_20220725" aria-hidden="true">#</a> 20220725</h2><p>灭蟑记（三）<sup class="footnote-ref"><a href="#footnote1">[1:2]</a><a class="footnote-anchor" id="footnote-ref1:2"></a></sup></p><p>丑时二刻，入庖厨环视，四处击而探之，无所见。遂入浴后起，听得耳边窸窣声，蟑螂也。拿拖鞋而反，不见，击探久之不得。方欲委去，复见其逃于隐辟。遂以神戒之，敌退我进，敌伏我杀，如此反复，其精疲力尽，终灭之一隅。</p><h2 id="_20220724" tabindex="-1"><a class="header-anchor" href="#_20220724" aria-hidden="true">#</a> 20220724</h2><p>灭蟑记（二）<sup class="footnote-ref"><a href="#footnote1">[1:3]</a><a class="footnote-anchor" id="footnote-ref1:3"></a></sup></p><p>今再遇一蟑，复震之，藏于一管内。管径二指，长半臂有余，震而不出。遂将此蟑以水冲入便器，然浮于水面，活蹦乱跳，久冲不下。覆纸其上，纸散，仍不灭。无奈，以器捞之，包于厚纸中受压而死，然后冲入水道，方得清净。呜呼！吾竟败与一蟑耳。</p><h2 id="_20220723" tabindex="-1"><a class="header-anchor" href="#_20220723" aria-hidden="true">#</a> 20220723</h2><p>灭蟑记（一）<sup class="footnote-ref"><a href="#footnote1">[1:4]</a><a class="footnote-anchor" id="footnote-ref1:4"></a></sup></p><p>熬夜欲睡，点灯入庖厨，直视右上橱柜，必有蟑螂因强光呆伏其上。遂取鞋，瓶碗却不可击。其一受惊震逃于墙上，命中当受此拖鞋劫。余一有大气运，入地即遁入狭间，视不可得。纸包蟑螂尸，入水道，欲绝后患。</p><h2 id="_20220718" tabindex="-1"><a class="header-anchor" href="#_20220718" aria-hidden="true">#</a> 20220718</h2><p>在空调房睡觉时混入了两只蚊子...已知蚊香液不能在密闭空间中使用，请问要保空调还是杀蚊子？<span class="heimu" title="你知道的太多了">我选择了后者</span></p><h2 id="_20220717" tabindex="-1"><a class="header-anchor" href="#_20220717" aria-hidden="true">#</a> 20220717</h2><p>无法适应规则，难以打破规则...那就绕过规则</p><h2 id="_20220712" tabindex="-1"><a class="header-anchor" href="#_20220712" aria-hidden="true">#</a> 20220712</h2>',22),w=e("h2",{id:"_20220708",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#_20220708","aria-hidden":"true"},"#"),a(" 20220708")],-1),y=n('<h2 id="_20220702" tabindex="-1"><a class="header-anchor" href="#_20220702" aria-hidden="true">#</a> 20220702</h2><p>感性的代价可不止一点呢...我究竟是为了什么回到家里来的啊...</p><h2 id="_20220629" tabindex="-1"><a class="header-anchor" href="#_20220629" aria-hidden="true">#</a> 20220629</h2><p>Github 治国有何不可！</p><h2 id="_20220628" tabindex="-1"><a class="header-anchor" href="#_20220628" aria-hidden="true">#</a> 20220628</h2><p>在模仿中重塑自我，在尝试中走出道路。</p><h2 id="_20220618" tabindex="-1"><a class="header-anchor" href="#_20220618" aria-hidden="true">#</a> 20220618</h2><p>能早解决的事就不要拖。不要像我这样垂死病中惊坐起发现论文已经过了 ddl 同时还发现 ip 不在学校不能免费看知网论文。（前几天一直在 <strong>享 受 假 期</strong> ） <img src="'+l+`" alt="绝望影像" loading="lazy"></p><h2 id="_20220613" tabindex="-1"><a class="header-anchor" href="#_20220613" aria-hidden="true">#</a> 20220613</h2><p>历经 11 天终于回到家了。这 11 天我的评价是很无聊，甚至不能给我的生命留下什么记忆。</p><h2 id="_20220612" tabindex="-1"><a class="header-anchor" href="#_20220612" aria-hidden="true">#</a> 20220612</h2><p>丈许浪大争西东，相击相灭一场空。</p><h2 id="_20220531" tabindex="-1"><a class="header-anchor" href="#_20220531" aria-hidden="true">#</a> 20220531</h2><p>回家路不过是名为隔离的笼子罢了。一时的感性还使我空虚。</p><h2 id="_20220529" tabindex="-1"><a class="header-anchor" href="#_20220529" aria-hidden="true">#</a> 20220529</h2><p>感性是需要代价的。纸魔给我的感性使我付出了代价。</p><h2 id="_20220522" tabindex="-1"><a class="header-anchor" href="#_20220522" aria-hidden="true">#</a> 20220522</h2><p>不使用杠杆原理的水龙头不是好水龙头。</p><h2 id="_20220521" tabindex="-1"><a class="header-anchor" href="#_20220521" aria-hidden="true">#</a> 20220521</h2><p>原来带给我满足与快感的不是爆肝，是创造！</p><h2 id="_20220519" tabindex="-1"><a class="header-anchor" href="#_20220519" aria-hidden="true">#</a> 20220519</h2><p>提防悄无声息的自我标准降低。</p><p>爆肝过后，满足与空虚一并涌上，想把成果分享给全世界，然后立刻开摆。</p><h2 id="_20220515" tabindex="-1"><a class="header-anchor" href="#_20220515" aria-hidden="true">#</a> 20220515</h2><p>在 Minecraft 中，人们追求更强的装备而忘记了建设家园的初衷；</p><p>在文艺作品中，反派渴望更强的力量而忘记了，身边的人。</p><h2 id="_20220514" tabindex="-1"><a class="header-anchor" href="#_20220514" aria-hidden="true">#</a> 20220514</h2><p>人类是很脆弱的。需要做好意外伤残甚至失去生命的觉悟。把幻想化为经验，预防悲剧发生。</p><h2 id="_20220513" tabindex="-1"><a class="header-anchor" href="#_20220513" aria-hidden="true">#</a> 20220513</h2><p>倘若遭遇绝望，也要去享受绝望。</p><h2 id="_20220510" tabindex="-1"><a class="header-anchor" href="#_20220510" aria-hidden="true">#</a> 20220510</h2><p>怎么会事呢？突然发现博客好像没什么东西写了 awa. ..前几天的干劲一定是用完了罢。对了，可以添加<code>atri</code>bot！</p><p>我恨不得每一天都能有 200 小时，不，2000 小时！</p><h2 id="_20220506" tabindex="-1"><a class="header-anchor" href="#_20220506" aria-hidden="true">#</a> 20220506</h2><p><code>cmd /k</code> : 执行命令，保留窗口</p><p>这里是启动<code>atri</code>bot 的关键脚本：</p><div class="language-batch line-numbers-mode" data-ext="batch"><pre class="language-batch"><code><span class="token command"><span class="token keyword">start</span> cmd <span class="token parameter attr-name">/K</span> <span class="token string">&quot;go-cqhttp.exe&quot;</span></span>
<span class="token command"><span class="token keyword">start</span> xxx.bat</span>
...
<span class="token command"><span class="token keyword">call</span> D:\\softwards\\Anaconda\\Scripts\\activate.bat D:\\softwards\\Anaconda</span>
<span class="token command"><span class="token keyword">call</span> conda activate lxl</span>
...
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><hr class="footnotes-sep"><section class="footnotes"><ol class="footnotes-list"><li id="footnote1" class="footnote-item"><p>这里是《灭蟑记》目录 <a href="#footnote-ref1" class="footnote-backref">↩︎</a> <a href="#footnote-ref1:1" class="footnote-backref">↩︎</a> <a href="#footnote-ref1:2" class="footnote-backref">↩︎</a> <a href="#footnote-ref1:3" class="footnote-backref">↩︎</a> <a href="#footnote-ref1:4" class="footnote-backref">↩︎</a></p></li></ol></section>`,39);function D(B,V){const r=s("RouterLink");return i(),o("div",null,[f,e("p",null,[a("由于我的两个 galgame 没法正常运行，我认定是不兼容 win11 的问题，花了几个小时去"),h(r,{to:"/articles/computer_setting.html"},{default:d(()=>[a("搞 hyper-v 虚拟机")]),_:1}),a("（毕竟是原生的，所以首选了）和出现的亿点 bug……最后还是没搞好，愤然选择 VMware 装上了 win10。结果发现玩不了 gal 的问题是 "),e("strong",null,[h(r,{to:"/blog/log.html#_20220815"},{default:d(()=>[a("20220815 硬盘崩了")]),_:1}),a("把文件损坏了")]),a("……笑死个人")]),u,e("p",null,[a("由于"),h(r,{to:"/hide/memories.html#%E5%A4%A7%E5%AD%A6-%E5%A4%A7%E4%B8%80%E5%90%8E%E6%9A%91%E5%81%87"},{default:d(()=>[a("一些原因")]),_:1}),a("，此间缺失的随笔统一算作今日随笔。")]),b,x,m,g,k,v,A,e("p",null,[h(r,{to:"/hide/memories.html#%E5%A4%A7%E5%AD%A6-%E5%A4%A7%E4%B8%80%E5%90%8E%E6%9A%91%E5%81%87"},{default:d(()=>[a("右耳聋了 7 天 5 小时")]),_:1}),a("，恢复听力后感慨：还是健康最重要啊。")]),E,e("p",null,[a("写"),h(r,{to:"/articles/track_record.html"},{default:d(()=>[a("（第二篇）横评")]),_:1}),a("时的那种掌控感有点爽（软件们在我手里瑟瑟发抖的样子. ..")]),w,e("p",null,[a("Android 的软件使用时长计时为什么只能查看本周数据...然后我做了个"),h(r,{to:"/articles/time_record.html"},{default:d(()=>[a("横评")]),_:1}),a("。")]),y])}const N=t(_,[["render",D],["__file","2022.html.vue"]]);export{N as default};
